def validate(args, output):
    num = args[0]
    if not isinstance(output, list):
        return False
    # does ANY valid split exist? brute-force search
    LIMIT = 2**31 - 1
    def find():
        n = len(num)
        def piece_ok(s):
            if len(s) > 1 and s[0] == '0':
                return None
            v = int(s)
            if v > LIMIT:
                return None
            return v
        # try first two pieces, then deterministically extend
        for i in range(1, n + 1):
            a = piece_ok(num[:i])
            if a is None:
                continue
            for j in range(i + 1, n + 1):
                b = piece_ok(num[i:j])
                if b is None:
                    continue
                seq = [a, b]
                k = j
                ok = True
                while k < n:
                    nxt = seq[-1] + seq[-2]
                    s = str(nxt)
                    if nxt > LIMIT or not num.startswith(s, k):
                        ok = False
                        break
                    seq.append(nxt)
                    k += len(s)
                if ok and k == n and len(seq) >= 3:
                    return True
        return False
    exists = find()
    if len(output) == 0:
        return not exists
    # non-empty: it must be a genuinely valid split
    if not exists:
        return False
    if len(output) < 3:
        return False
    for v in output:
        if not isinstance(v, int) or isinstance(v, bool):
            return False
        if v < 0 or v > LIMIT:
            return False
    for i in range(len(output) - 2):
        if output[i] + output[i + 1] != output[i + 2]:
            return False
    parts = []
    for v in output:
        s = str(v)
        parts.append(s)
    if ''.join(parts) != num:
        return False
    for s in parts:
        if len(s) > 1 and s[0] == '0':
            return False
    return True

