function validate(args, output) {
    const num = args[0];
    if (!Array.isArray(output)) return false;
    const LIMIT = 2147483647;
    function pieceOk(s) {
        if (s.length > 1 && s[0] === '0') return null;
        const v = Number(s);
        if (v > LIMIT) return null;
        return v;
    }
    function find() {
        const n = num.length;
        for (let i = 1; i <= n; i++) {
            const a = pieceOk(num.slice(0, i));
            if (a === null) continue;
            for (let j = i + 1; j <= n; j++) {
                const b = pieceOk(num.slice(i, j));
                if (b === null) continue;
                const seq = [a, b];
                let k = j;
                let ok = true;
                while (k < n) {
                    const nxt = seq[seq.length - 1] + seq[seq.length - 2];
                    const s = String(nxt);
                    if (nxt > LIMIT || !num.startsWith(s, k)) { ok = false; break; }
                    seq.push(nxt);
                    k += s.length;
                }
                if (ok && k === n && seq.length >= 3) return true;
            }
        }
        return false;
    }
    const exists = find();
    if (output.length === 0) return !exists;
    if (!exists) return false;
    if (output.length < 3) return false;
    for (const v of output) {
        if (typeof v !== 'number' || !Number.isInteger(v)) return false;
        if (v < 0 || v > LIMIT) return false;
    }
    for (let i = 0; i < output.length - 2; i++) {
        if (output[i] + output[i + 1] !== output[i + 2]) return false;
    }
    let joined = '';
    for (const v of output) joined += String(v);
    if (joined !== num) return false;
    for (const v of output) {
        const s = String(v);
        if (s.length > 1 && s[0] === '0') return false;
    }
    return true;
}

