class Solution:
    def splitIntoFibonacci(self, num):
        LIMIT = 2**31 - 1
        n = len(num)
        result = []
        def backtrack(idx, seq):
            if idx == n:
                return len(seq) >= 3
            for end in range(idx + 1, n + 1):
                s = num[idx:end]
                if len(s) > 1 and s[0] == '0':
                    break
                v = int(s)
                if v > LIMIT:
                    break
                if len(seq) >= 2 and v != seq[-1] + seq[-2]:
                    if v > seq[-1] + seq[-2]:
                        break
                    continue
                seq.append(v)
                if backtrack(end, seq):
                    return True
                seq.pop()
            return False
        if backtrack(0, result):
            return result
        return []

